import{_ as a,o as l,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"中国 AI 推理芯片创业公司量产进度与订单追踪","description":"","frontmatter":{},"headers":[],"relativePath":"AI/_深化_2026-06-16_中国AI推理芯片量产进度.md","filePath":"AI/_深化_2026-06-16_中国AI推理芯片量产进度.md","lastUpdated":1781602495000}'),o={name:"AI/_深化_2026-06-16_中国AI推理芯片量产进度.md"};function n(s,t,e,d,h,g){return l(),i("div",null,[...t[0]||(t[0]=[r(`<h1 id="中国-ai-推理芯片创业公司量产进度与订单追踪" tabindex="-1">中国 AI 推理芯片创业公司量产进度与订单追踪 <a class="header-anchor" href="#中国-ai-推理芯片创业公司量产进度与订单追踪" aria-label="Permalink to &quot;中国 AI 推理芯片创业公司量产进度与订单追踪&quot;">​</a></h1><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h2><p>三家国产 GPU/AI 芯片创业公司均已实现量产并获得真实商业订单，且均已完成上市（2025 年底至 2026 年初）。壁仞科技在手订单 12.41 亿元，客户含 9 家财富中国 500 强；摩尔线程 2026Q1 营收 7.38 亿元（+155%），单季盈利；沐曦股份在手订单 14.3 亿元。竞争焦点从芯片规格转向单位 token 成本、软件生态和客户深度绑定。国内主要科技平台 2026 年 AI 资本开支预计达 5970 亿元（+38%）。</p><h2 id="各公司详解" tabindex="-1">各公司详解 <a class="header-anchor" href="#各公司详解" aria-label="Permalink to &quot;各公司详解&quot;">​</a></h2><h3 id="壁仞科技-港股-gpu-第一股" tabindex="-1">壁仞科技（港股 GPU 第一股） <a class="header-anchor" href="#壁仞科技-港股-gpu-第一股" aria-label="Permalink to &quot;壁仞科技（港股 GPU 第一股）&quot;">​</a></h3><ul><li><strong>上市</strong>：2026 年 1 月港交所主板（代码 6082），首日开盘涨 82%</li><li><strong>估值</strong>：约 209 亿元</li><li><strong>产品线</strong>： <ul><li>BR106（2023 量产）：数据中心 AI 训练+推理</li><li>BR110（2024 量产）：边缘场景，高能效比</li><li>BR166（2025 量产）：性能为 BR106 两倍</li><li>BR20X（2026 商业化）：第二代自研架构，原生支持 FP8/FP4</li></ul></li><li><strong>订单</strong>：截至 2025.12.15，在手 12.41 亿元（5 份框架协议 + 24 份销售合约）</li><li><strong>客户</strong>：9 家财富中国 500 强企业，包括三大电信运营商</li><li><strong>亮点</strong>：三款 GPGPU 已连续量产，切入运营商智算集群供应链</li></ul><h3 id="摩尔线程-科创板-gpu-龙头" tabindex="-1">摩尔线程（科创板 GPU 龙头） <a class="header-anchor" href="#摩尔线程-科创板-gpu-龙头" aria-label="Permalink to &quot;摩尔线程（科创板 GPU 龙头）&quot;">​</a></h3><ul><li><strong>上市</strong>：2025 年底科创板，首日暴涨超 4 倍</li><li><strong>2025 年营收</strong>：15.06 亿元（+243%）</li><li><strong>2026Q1 营收</strong>：7.38 亿元（+155%）</li><li><strong>盈利</strong>：2026Q1 归母净利润首次实现单季度盈利</li><li><strong>大单</strong>：6.6 亿元夸娥（KUAE）智算集群销售合同（2026 年 3 月）</li><li><strong>技术</strong>：MTT S5000 训推一体 GPU，单卡稠密算力 1000 TFLOPS，80GB 显存</li><li><strong>生态</strong>：MUSA 架构兼容 CUDA 生态，率先适配 DeepSeek V4</li><li><strong>能力</strong>：从单卡 → 千卡/万卡集群 → 端到端交付的商业闭环</li></ul><h3 id="沐曦股份-科创板-ai-芯片新锐" tabindex="-1">沐曦股份（科创板 AI 芯片新锐） <a class="header-anchor" href="#沐曦股份-科创板-ai-芯片新锐" aria-label="Permalink to &quot;沐曦股份（科创板 AI 芯片新锐）&quot;">​</a></h3><ul><li><strong>上市</strong>：2025 年 12 月科创板</li><li><strong>2026Q1 营收</strong>：5.62 亿元（+75.37%）</li><li><strong>产品</strong>：曦云 C500 系列（收入占比 90%+），曦云 C600 全国产工艺风险量产</li><li><strong>在手订单</strong>：14.30 亿元（截至 2025.9，以 C500 板卡为主）</li><li><strong>客户</strong>：进入中国电信集采短名单，互联网大客户预订单已下</li><li><strong>预计</strong>：2026Q2 启动出货，下半年大幅放量，2026-2027 年贡献超 40 亿元营收</li><li><strong>特色</strong>：全国产供应链闭环（设计-制造-封测），面向金融/政务等高安全场景</li></ul><h3 id="寒武纪" tabindex="-1">寒武纪 <a class="header-anchor" href="#寒武纪" aria-label="Permalink to &quot;寒武纪&quot;">​</a></h3><ul><li><strong>2026Q1 营收</strong>：同比 +160%</li><li><strong>评级</strong>：摩根士丹利给予增持，称寒武纪是&quot;AI 推理芯片领先标的&quot;</li><li><strong>竞争逻辑</strong>：胜负不再由芯片规格决定，而是单位 token 成本经济性、软件生态成熟度、客户深度绑定</li></ul><h2 id="财务对比" tabindex="-1">财务对比 <a class="header-anchor" href="#财务对比" aria-label="Permalink to &quot;财务对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>公司</th><th>上市地</th><th>2025 年营收</th><th>2026Q1 营收</th><th>在手订单</th><th>盈利状况</th></tr></thead><tbody><tr><td>壁仞科技</td><td>港股</td><td>N/A</td><td>N/A</td><td>12.41 亿</td><td>未披露</td></tr><tr><td>摩尔线程</td><td>科创板</td><td>15.06 亿</td><td>7.38 亿</td><td>6.6 亿（单笔）</td><td>单季盈利</td></tr><tr><td>沐曦股份</td><td>科创板</td><td>N/A</td><td>5.62 亿</td><td>14.3 亿</td><td>减亏中</td></tr><tr><td>寒武纪</td><td>A 股</td><td>N/A</td><td>+160%</td><td>N/A</td><td>N/A</td></tr></tbody></table><h2 id="竞争格局演变" tabindex="-1">竞争格局演变 <a class="header-anchor" href="#竞争格局演变" aria-label="Permalink to &quot;竞争格局演变&quot;">​</a></h2><p>竞争焦点已从单一芯片规格转向&quot;全栈能力&quot;：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第一阶段 (2023-2024): 芯片能不能跑 → 规格竞赛</span></span>
<span class="line"><span>第二阶段 (2025): 谁有量产订单 → 商业化验证</span></span>
<span class="line"><span>第三阶段 (2026+): 谁的生态好用 + 单位token成本低 → 生态竞赛</span></span></code></pre></div><ul><li><strong>字节等大客户批量采购</strong>国产 AI 芯片用于推理</li><li><strong>全栈能力</strong>（芯片+系统+软件+集群交付）成为壁垒</li><li><strong>中国 AI 资本开支</strong>：主要科技平台 2026 年预计 5970 亿元（+38%），2030 年市场规模巨大</li><li><strong>ASIC 路线竞争</strong>：推理场景下 ASIC 有一定能效比优势，但生态兼容性受限制</li></ul><h2 id="后续上市企业" tabindex="-1">后续上市企业 <a class="header-anchor" href="#后续上市企业" aria-label="Permalink to &quot;后续上市企业&quot;">​</a></h2><ul><li><strong>天数智芯</strong>：计划 2026 年 1 月港股上市</li><li><strong>燧原科技</strong>：2025 年 11 月重新上市辅导备案，辅导已完成</li><li><strong>2025 年底至 2026 年初</strong>：国产算力芯片企业集体冲刺资本市场</li></ul><h2 id="风险提示" tabindex="-1">风险提示 <a class="header-anchor" href="#风险提示" aria-label="Permalink to &quot;风险提示&quot;">​</a></h2><ol><li>英伟达出口管制变化可能打乱国产芯片迭代节奏</li><li>软件生态成熟度仍与 CUDA 有差距</li><li>部分企业仍处亏损状态，盈利能力待验证</li><li>大规模集群交付能力仍是工程化瓶颈（摩尔线程已先行突破）</li><li>单位 token 成本竞争加剧可能压缩毛利率</li></ol><hr><p><em>来源：36氪、钛媒体、界面新闻、东方财富网、腾讯新闻</em><em>更新：2026-06-16</em></p>`,24)])])}const _=a(o,[["render",n]]);export{c as __pageData,_ as default};
